        if old_val and old_val != 'None':
            agent_transferred[old_val] = agent_transferred.get(old_val, 0) + 1

# Filter
eligible = []
for agent, count in agent_handled.items():
    if count > 0:
        t_count = agent_transferred.get(agent, 0)
